# API router: header-based version routing during grace period
from fastapi import APIRouter, Header, HTTPException
from typing import Optional
import datetime

router = APIRouter()

GRACE_PERIOD_END = datetime.date(2026, 10, 1)

@router.post("/summarize")
async def summarize(
    request: SummarizeRequest,
    x_prompt_version: Optional[str] = Header(default=None),
):
    today = datetime.date.today()

    # During grace period: default to v2 if no header specified
    # After hard sunset: v2 no longer available
    if today >= GRACE_PERIOD_END and x_prompt_version in (None, "v2"):
        raise HTTPException(
            status_code=410,
            detail="prompt-summarization-v2 has been sunset. Use v3.",
            headers={"Link": '</api/v3/summarize>; rel="successor-version"'},
        )

    version = x_prompt_version or "v2"  # default to v2 during grace period

    if version == "v2":
        return await handle_v2(request)
    elif version == "v3":
        return await handle_v3(request)
    else:
        raise HTTPException(status_code=400, detail=f"Unknown prompt version: {version}")
